sql:
SELECT a.article_title, a.quiz_task_uuid, a.question_type, q.question_text
FROM articles a
LEFT JOIN questions q ON a.question_type = q.question_type;

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN coding_agreements ca ON u.user_id = ca.user_id;

SELECT COUNT(DISTINCT users.user_id)
FROM users
JOIN assessor_comments ON users.user_id = assessor_comments.user_id;

SELECT COUNT(*) 
FROM articles 
WHERE article_id = 1;

SELECT article_authors, article_title
FROM articles
WHERE article_publication_date > '2022-01-01';

SELECT comment_text 
FROM assessor_comments 
WHERE user_id IN (SELECT article_id FROM articles);

SELECT comment_text
FROM assessor_comments
WHERE comment_id = 1;

SELECT UPPER(users.user_name) AS UserName, answers.answer_content AS AnswerContent 
FROM users 
JOIN answers ON users.user_id = answers.answer_id;

external_knowledge:
- "sailors" refers to the users in the `users` table;
- "charted a course" metaphorically refers to participating in coding tasks;
- "consensus among navigators" metaphorically refers to the percentage agreement among coders;
- "exceeds the halfway mark" means the average percentage agreement is greater than 50%.
